#include <bits/stdc++.h>
using namespace std;
int a[100005],n;
set <int> s;
struct node
{
	vector<int> v;
	int time;
} b[100005];
int st=0;
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		int k;
		cin>>b[i].time>>k;
		while(k--)
		{
			int t;
			cin>>t;
			b[i].v.push_back(t);
			s.insert(t);
			a[t]++;
		}
		for(;b[st].time<=b[i].time-86400;st++)
		{
			vector<int> v1=b[st].v;
			for(int j=0;j<v1.size();j++)
			{
				a[v1[j]]--;
				if(a[v1[j]]==0) s.erase(v1[j]);
			}
		}
		cout<<s.size()<<'\n';
	}
	return 0;
}
